const staticData = $getWorkflowStaticData('global');
staticData.c24Day = staticData.c24Day || {};

const item = $input.first().json;
const sid = String(item.sessionId || 'anon');
const today = new Date().toISOString().slice(0, 10);

const prev = staticData.c24Day[sid];
const isFirstToday = prev !== today;
staticData.c24Day[sid] = today;

const raw = String(item.chatInput || '').trim();
const lines = raw
  .split(/\r?\n/)
  .map((s) => s.trim())
  .filter((s) => {
    if (!s) return false;
    if (/^\d{1,2}:\d{2}$/.test(s)) return false;
    if (/^-{3,}$/.test(s)) return false;
    if (/^you are trained on data up to/i.test(s)) return false;
    return true;
  });

let latest = raw;
const lastTranslateIdx = lines.map((s) => s.toLowerCase()).lastIndexOf('(translate)');
if (lastTranslateIdx >= 0 && lines[lastTranslateIdx + 1]) {
  latest = lines[lastTranslateIdx + 1];
} else if (lines.length) {
  latest = lines[lines.length - 1];
}

return [
  {
    json: {
      ...item,
      chatInput: latest,
      firstToday: isFirstToday,
      useCanned: false,
    },
  },
];

const cur = $input.first().json;
let reply = String(cur.reply ?? cur.output ?? cur.text ?? '').trim();

let prepare = {};
try {
  prepare = $('Prepare reply').first().json;
} catch (e) {}

const days = [
  'Sunday',
  'Monday',
  'Tuesday',
  'Wednesday',
  'Thursday',
  'Friday',
  'Saturday',
];
const weekday = days[new Date().getDay()];
const prefix = 'Hey buddy\nHappy ' + weekday + '!';
const signoff = 'Sarah\nalientime.sg';

// Remove accidental duplicated/placeholder greeting from model output.
reply = reply.replace(/^Hey buddy\s*\n\s*Happy\s*\[[^\]]+\]!\s*/i, '').trim();
if (reply.toLowerCase().startsWith('hey buddy\nhappy ' + weekday.toLowerCase() + '!')) {
  reply = reply.slice(prefix.length).trim();
}

// Remove classification labels if model outputs them.
reply = reply
  .replace(/^(general|technical|special)\s*[—:\-]?\s*/i, '')
  .replace(/^classification\s*[—:\-]?\s*(general|technical|special)\s*[—:\-]?\s*/i, '')
  .trim();

if (prepare.firstToday === true) {
  reply = prefix + '\n\n' + reply;
}

if (!reply.toLowerCase().endsWith(signoff.toLowerCase())) {
  reply = reply + '\n' + signoff;
}

let replyChannel = 'http';
try {
  if (prepare.replyChannel) {
    replyChannel = prepare.replyChannel;
  }
} catch (e) {}
try {
  const rows = $('HTTP entry').all();
  if (rows.length && rows[0].json.replyChannel) {
    replyChannel = rows[0].json.replyChannel;
  }
} catch (e) {}

return [{ json: { reply, replyChannel } }];
